void hide_toast_timer_cb(lv_timer_t * timer)
{
    // 1. 从定时器里把咱们传进去的面板取出来
    lv_obj_t * panel = (lv_obj_t *)timer->user_data;
    
    // 2. 给这个面板加上“隐藏”标志
    if(panel != NULL) {
        lv_obj_add_flag(panel, LV_OBJ_FLAG_HIDDEN);
    }
}

